"use client";
import React from "react";

function ProductsAndCategoryLayout({ products, categories, children }) {
  return (
    <div className="mt-20">
      <section className="px-6 md:px-8 py-8">
        <div className="mb-8">{categories}</div>
      </section>
      <section className="px-6 md:px-8 py-8 gap-6">
        <div className="mb-0">{products}</div>
      </section>
      {children}
    </div>
  );
}

export default ProductsAndCategoryLayout;
